// Tier 3 · Pair A — build the version-N fleet corpus.
//
//   node eval/fleet-study/tier3/pair-a/make-fleet.mjs
//
// The corpus is every state reachable from `init` under the FROZEN v2.4.0
// translation. That is the set of states a Medusa fleet running v2.4.0 could
// hold at the moment v2.5.0 is deployed.
//
// PROVENANCE, stated up front because it bounds every claim built on it.
// This corpus is `upstream-model` — generated by the version-N translation,
// not captured from a running Medusa. Under the Tier 1/2 discipline that is
// the WEAKEST tier: a corpus the model produced cannot be independent evidence
// about that model. tier3-protocol §5 permits it as the fallback where
// standing up a version is impractical, and requires it be labelled, never as
// `live`.
//
// What it can still do is answer Pair A's actual question, which is not about
// the model's fidelity but about COMPATIBILITY: given the states v2.4.0's own
// rules say are legal, does v2.5.0 accept them? For that question a
// model-generated corpus is sound, because the states are exactly the ones
// v2.4.0 declares reachable — and the translation over-approximates (see
// VALIDATION.md §6), so the corpus is if anything harder on v2.5.0 than a real
// fleet would be.
'use strict';

import { writeFileSync, mkdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createRequire } from 'node:module';

const here = dirname(fileURLToPath(import.meta.url));
const require = createRequire(import.meta.url);
const m = require(join(here, 'v2.4.0', 'next.cjs'));

const DOMAIN = {
  ADD_SESSION: [{}],
  AUTHORIZE_SESSION: [{ level: 'partial' }, { level: 'full' }],
  CAPTURE_PAYMENT: [{ level: 'partial' }, { level: 'full' }],
  REFUND_PAYMENT: [{ level: 'partial' }, { level: 'full' }],
  CANCEL_ORDER: [{}],
};

m.init();
const start = JSON.stringify(m.getState());
const seen = new Map([[start, JSON.parse(start)]]);
const queue = [start];

while (queue.length) {
  const cur = queue.shift();
  for (const [action, datas] of Object.entries(DOMAIN)) {
    for (const data of datas) {
      m.setState(JSON.parse(cur));
      m.actions[action](data);
      const next = m.getState();
      const key = JSON.stringify(next);
      if (!seen.has(key)) { seen.set(key, next); queue.push(key); }
    }
  }
}

const entries = [...seen.values()].map((state, i) => ({ id: `medusa-v2.4.0#${i}`, state }));
const byStatus = entries.reduce((a, e) => ({ ...a, [e.state.status]: (a[e.state.status] ?? 0) + 1 }), {});

mkdirSync(join(here, 'out'), { recursive: true });
writeFileSync(join(here, 'out', 'fleet.json'), JSON.stringify(entries, null, 2) + '\n');
writeFileSync(join(here, 'out', 'manifest.json'), JSON.stringify({
  tier: 3, pair: 'A', versionN: 'v2.4.0',
  upstreamCommit: '956a50e934fb0db6f55d5b9fa459a43abcee358b',
  provenance: 'upstream-model (generated by the FROZEN v2.4.0 translation — not captured from a running Medusa)',
  admissibleAsLiveFleet: false,
  count: entries.length, byStatus,
  note: 'Sound for the compatibility question (are v2.4.0-legal states accepted by v2.5.0?), which is what Pair A asks. Not evidence about the translation\'s fidelity to Medusa — that is VALIDATION.md\'s job.',
}, null, 2) + '\n');

console.log(`fleet: ${entries.length} distinct states`);
console.log('by status:', Object.entries(byStatus).map(([k, v]) => `${k}=${v}`).join(' '));
// The state Pair A hinges on: fully captured, yet still `authorized`, because
// at v2.4.0 capture does not move the status.
const fullyCaptured = entries.filter((e) => e.state.captured === 'full');
console.log(`\nfully-captured states (${fullyCaptured.length}) and the status v2.4.0 leaves them in:`);
for (const e of fullyCaptured) console.log(`  ${e.id}  status=${e.state.status}  authorized=${e.state.authorized}`);
